class SecureXMLParser {
  def parseXML(xmlString: String): Try[Elem] = Try {
    val factory = SAXParserFactory.newInstance()
    factory.setFeature("http://xml.org/sax/features/external-general-entities", false)
    factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false)
    factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true)
    factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false)
    factory.setXIncludeAware(false)
    factory.setNamespaceAware(true)
    
    val parser = factory.newSAXParser()
    val adapter = new parsing.NoBindingFactoryAdapter
    val source = new org.xml.sax.InputSource(new StringReader(xmlString))
    
    adapter.loadXML(source, parser)
  }
}

class ConfigurationParser {
  private val secureParser = new SecureXMLParser()
  
  def parseConfiguration(xmlString: String): Try[ConfigurationSettings] = {
    secureParser.parseXML(xmlString).flatMap { elem =>
      Try {
        extractConfiguration(elem)
      }
    }
  }
  
  private def extractConfiguration(elem: Elem): ConfigurationSettings = {
    val name = (elem \ "@name").text
    val version = (elem \ "@version").headOption.map(_.text).getOrElse("1.0")
    
    val properties = (elem \ "property").map { prop =>
      val key = (prop \ "@key").text
      val value = (prop \ "@value").headOption.map(_.text).getOrElse(prop.text)
      key -> value
    }.toMap
    
    val nestedConfigs = (elem \ "configuration").map { nested =>
      extractConfiguration(nested.asInstanceOf[Elem])
    }.toList
    
    ConfigurationSettings(name, version, properties, nestedConfigs)
  }
  
  def parseConfigurationWithEntityResolution(xmlString: String, entityResolver: Map[String, String]): Try[ConfigurationSettings] = {
    val resolvedXml = resolveEntities(xmlString, entityResolver)
    parseConfiguration(resolvedXml)
  }
  
  private def resolveEntities(xmlString: String, entities: Map[String, String]): String = {
    var result = xmlString
    entities.foreach { case (key, value) =>
      result = result.replace(s"&$key;", value)
    }
    result
  }
}

class ConfigurationService {
  private val parser = new ConfigurationParser()
  
  def processConfigurationRequest(xmlContent: String): Either[String, ConfigurationSettings] = {
    parser.parseConfiguration(xmlContent) match {
      case Success(config) => Right(config)
      case Failure(ex) => Left(s"Failed to parse configuration: ${ex.getMessage}")
    }
  }
  
  def processConfigurationWithEntities(
    xmlContent: String, 
    entities: Map[String, String]
  ): Either[String, ConfigurationSettings] = {
    parser.parseConfigurationWithEntityResolution(xmlContent, entities) match {
      case Success(config) => Right(config)
      case Failure(ex) => Left(s"Failed to parse configuration with entities: ${ex.getMessage}")
    }
  }
  
  def extractSetting(config: ConfigurationSettings, key: String): Option[String] = {
    config.properties.get(key).orElse {
      config.nestedSettings.flatMap(nested => extractSetting(nested, key)).headOption
    }
  }
  
  def getAllSettings(config: ConfigurationSettings): Map[String, String] = {
    val nested = config.nestedSettings.flatMap(getAllSettings).toMap
    config.properties ++ nested
  }
  
  def validateConfiguration(config: ConfigurationSettings, requiredKeys: Set[String]): Either[String, ConfigurationSettings] = {
    val allSettings = getAllSettings(config)
    val missingKeys = requiredKeys.filterNot(allSettings.contains)
    
    if (missingKeys.isEmpty) {
      Right(config)
    } else {
      Left(s"Missing required configuration keys: ${missingKeys.mkString(", ")}")
    }
  }
  
  def mergeConfigurations(configs: List[ConfigurationSettings]): ConfigurationSettings = {
    configs match {
      case Nil => ConfigurationSettings("empty", "1.0", Map.empty)
      case head :: tail =>
        tail.foldLeft(head) { (acc, config) =>
          ConfigurationSettings(
            name = acc.name,
            version = acc.version,
            properties = acc.properties ++ config.properties,
            nestedSettings = acc.nestedSettings ++ config.nestedSettings
          )
        }
    }
  }
  
  def filterSettingsByPrefix(config: ConfigurationSettings, prefix: String): Map[String, String] = {
    getAllSettings(config).filter { case (key, _) => key.startsWith(prefix) }
  }
  
  def getNestedConfiguration(config: ConfigurationSettings, name: String): Option[ConfigurationSettings] = {
    config.nestedSettings.find(_.name == name).orElse {
      config.nestedSettings.flatMap(nested => getNestedConfiguration(nested, name)).headOption
    }
  }
}

